import jwt
from jwt import PyJWKClient

def decode_jwt(token):
    try:
        headers = jwt.get_unverified_header(token)
        kid = headers['kid']
        
        # Specify your Auth0 domain to fetch the key from
        jwks_url = "https://<Your-Auth0-Domain>.com/.well-known/jwks.json"
        jwks_client = PyJWKClient(jwks_url)
        
        public_key = jwks_client.get_signing_key(kid).to_pem()

        # Decodes the token with the key and returns payload
        decoded = jwt.decode(token, public_key, algorithms=['RS256'])
        
        return decoded
    except Exception as e:
        print("Error while decoding JWT : ", str(e))
        return None